SELECT title
FROM movies
WHERE revenue = (SELECT MAX(revenue) FROM movies);

SELECT SUM(CAST(REPLACE(REPLACE(m.budget, ',', ''), '$', '') AS REAL)) AS total_budget
FROM movies m
WHERE m.director = 'Frank Darabont';

SELECT DISTINCT m.title
FROM movies m
JOIN awards a ON m.movie_id = a.movie_id;
